import React, { useEffect, useRef, useState } from 'react'
import maplibregl from 'maplibre-gl'
import { Columns } from 'lucide-react'
import { useMapStore } from '../../store/useMapStore'
import 'maplibre-gl/dist/maplibre-gl.css'

const MapContainer: React.FC = () => {
  const mapContainerLeft = useRef<HTMLDivElement>(null)
  const mapContainerRight = useRef<HTMLDivElement>(null)
  const mapLeft = useRef<maplibregl.Map | null>(null)
  const mapRight = useRef<maplibregl.Map | null>(null)
  const { longitude, latitude, zoom, pitch, bearing, setViewState, activeLayers, changeResults, mapTheme } = useMapStore()
  
  const [splitPosition, setSplitPosition] = useState(50)
  const [isMapLoaded, setIsMapLoaded] = useState(false)
  const isSplitMode = activeLayers.includes('changes')

  useEffect(() => {
    if (!mapContainerLeft.current || !mapContainerRight.current) return

    const sharedStyle = {
      version: 8,
      sources: {
        'light-matter': {
          type: 'raster',
          tiles: [
            'https://a.basemaps.cartocdn.com/light_all/{z}/{x}/{y}.png',
            'https://b.basemaps.cartocdn.com/light_all/{z}/{x}/{y}.png',
            'https://c.basemaps.cartocdn.com/light_all/{z}/{x}/{y}.png'
          ],
          tileSize: 256,
          attribution: '&copy; <a href="https://carto.com/">CARTO</a>'
        }
      },
      layers: [
        {
          id: 'light-matter-layer',
          type: 'raster',
          source: 'light-matter',
          paint: {
            'raster-opacity': 1.0
          }
        }
      ]
    };

    mapLeft.current = new maplibregl.Map({
      container: mapContainerLeft.current,
      style: sharedStyle as any,
      center: [longitude, latitude],
      zoom: zoom,
      pitch: pitch,
      bearing: bearing,
      attributionControl: false
    })

    mapRight.current = new maplibregl.Map({
      container: mapContainerRight.current,
      style: sharedStyle as any,
      center: [longitude, latitude],
      zoom: zoom,
      pitch: pitch,
      bearing: bearing,
      attributionControl: false
    })

    // Add controls to right map (which sits on top)
    mapRight.current.addControl(new maplibregl.NavigationControl({ showCompass: false }), 'bottom-right')

    let loadedCount = 0;
    const checkLoaded = () => {
      loadedCount++;
      if (loadedCount === 2) setIsMapLoaded(true);
    };

    mapLeft.current.on('load', checkLoaded)
    mapRight.current.on('load', checkLoaded)

    let isSyncingLeft = false;
    let isSyncingRight = false;

    mapLeft.current.on('move', () => {
      if (!mapLeft.current || !mapRight.current) return;
      if (isSyncingRight) return;
      isSyncingLeft = true;
      mapRight.current.jumpTo({
        center: mapLeft.current.getCenter(),
        zoom: mapLeft.current.getZoom(),
        bearing: mapLeft.current.getBearing(),
        pitch: mapLeft.current.getPitch()
      })
      isSyncingLeft = false;

      const center = mapLeft.current.getCenter()
      setViewState({
        longitude: center.lng,
        latitude: center.lat,
        zoom: mapLeft.current.getZoom(),
        pitch: mapLeft.current.getPitch(),
        bearing: mapLeft.current.getBearing()
      })
    })

    mapRight.current.on('move', () => {
      if (!mapLeft.current || !mapRight.current) return;
      if (isSyncingLeft) return;
      isSyncingRight = true;
      mapLeft.current.jumpTo({
        center: mapRight.current.getCenter(),
        zoom: mapRight.current.getZoom(),
        bearing: mapRight.current.getBearing(),
        pitch: mapRight.current.getPitch()
      })
      isSyncingRight = false;
    })

    // Setup ResizeObserver to fix distortion when Sidebar opens/closes
    const resizeObserver = new ResizeObserver(() => {
      mapLeft.current?.resize()
      mapRight.current?.resize()
    })
    resizeObserver.observe(mapContainerLeft.current)

    return () => {
      resizeObserver.disconnect()
      mapLeft.current?.remove()
      mapRight.current?.remove()
    }
  }, [])

  // Sync external state changes gracefully to avoid stutter loops
  useEffect(() => {
    if (mapLeft.current && isMapLoaded) {
      const center = mapLeft.current.getCenter()
      const currentZoom = mapLeft.current.getZoom()
      
      const dist = Math.sqrt(Math.pow(center.lng - longitude, 2) + Math.pow(center.lat - latitude, 2))
      if (dist > 0.05 || Math.abs(currentZoom - zoom) > 0.5) {
        mapLeft.current.flyTo({
          center: [longitude, latitude],
          zoom,
          pitch,
          bearing,
          duration: 1500,
          essential: true
        })
      }
    }
  }, [longitude, latitude, zoom, pitch, bearing, isMapLoaded])

  // Handle layer toggles
  useEffect(() => {
    if (!mapLeft.current || !mapRight.current || !isMapLoaded) return
    
    const maps = [mapLeft.current, mapRight.current]

    maps.forEach((mapInstance) => {
      // Authentic Side-By-Side Satellite Imagery Setup
      if (activeLayers.includes('satellite')) {
        // LEFT MAP (Baseline - using Google Satellite proxy for temporal offset)
        if (mapLeft.current && !mapLeft.current.getSource('satellite')) {
          mapLeft.current.addSource('satellite', {
            type: 'raster',
            tiles: ['https://mt1.google.com/vt/lyrs=s&x={x}&y={y}&z={z}'],
            tileSize: 256,
            attribution: '&copy; Google'
          })
          mapLeft.current.addLayer({
            id: 'satellite-layer',
            type: 'raster',
            source: 'satellite',
            paint: { 'raster-opacity': 1.0 }
          }, mapLeft.current.getLayer('boundaries-layer') ? 'boundaries-layer' : undefined)
        }

        // RIGHT MAP (Current - using Esri World Imagery)
        if (mapRight.current && !mapRight.current.getSource('satellite')) {
          mapRight.current.addSource('satellite', {
            type: 'raster',
            tiles: [
              'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}'
            ],
            tileSize: 256,
            attribution: '&copy; Esri'
          })
          mapRight.current.addLayer({
            id: 'satellite-layer',
            type: 'raster',
            source: 'satellite',
            paint: { 'raster-opacity': 1.0 }
          }, mapRight.current.getLayer('boundaries-layer') ? 'boundaries-layer' : undefined)
        }
      } else {
        maps.forEach(mapInstance => {
          if (mapInstance.getLayer('satellite-layer')) mapInstance.removeLayer('satellite-layer')
          if (mapInstance.getSource('satellite')) mapInstance.removeSource('satellite')
        })
      }
      
      // Admin Boundaries
      if (activeLayers.includes('boundaries')) {
        if (!mapInstance.getSource('boundaries')) {
          mapInstance.addSource('boundaries', {
            type: 'geojson',
            data: 'https://d2ad6b4ur7yvpq.cloudfront.net/naturalearth-3.3.0/ne_110m_admin_0_countries.geojson'
          })
          mapInstance.addLayer({
            id: 'boundaries-layer',
            type: 'line',
            source: 'boundaries',
            paint: {
              'line-color': '#000000',
              'line-width': 1.5,
              'line-opacity': 0.8
            }
          })
        }
      } else {
        if (mapInstance.getLayer('boundaries-layer')) mapInstance.removeLayer('boundaries-layer')
        if (mapInstance.getSource('boundaries')) mapInstance.removeSource('boundaries')
      }

      // Population Density
      if (activeLayers.includes('population')) {
        if (!mapInstance.getSource('population')) {
          mapInstance.addSource('population', {
            type: 'raster',
            tiles: [
              'https://tiles.arcgis.com/tiles/P3ePLMYs2RVChkJx/arcgis/rest/services/World_Population_Density/MapServer/tile/{z}/{y}/{x}'
            ],
            tileSize: 256,
            attribution: '&copy; Esri, WorldPop'
          })
          mapInstance.addLayer({
            id: 'population-layer',
            type: 'raster',
            source: 'population',
            paint: { 'raster-opacity': 0.7 }
          }, mapInstance.getLayer('boundaries-layer') ? 'boundaries-layer' : undefined)
        }
      } else {
        if (mapInstance.getLayer('population-layer')) mapInstance.removeLayer('population-layer')
        if (mapInstance.getSource('population')) mapInstance.removeSource('population')
      }
    })

    // Change Detection Overlay ONLY ON RIGHT MAP (Current Mode)
    const sourceId = 'simulated-changes'
    const fillLayerId = 'simulated-changes-fill'
    const lineLayerId = 'simulated-changes-line'
    const rightMap = mapRight.current

    if (activeLayers.includes('changes') && changeResults.length > 0) {
      const geojsonData = {
        type: 'FeatureCollection',
        features: changeResults.map((c: any) => ({
          type: 'Feature',
          geometry: c.geometry,
          properties: {
            confidence: c.confidence,
            type: c.change_type,
            area: c.area_sq_meters
          }
        }))
      }

      if (!rightMap.getSource(sourceId)) {
        rightMap.addSource(sourceId, {
          type: 'geojson',
          data: geojsonData as any
        })
        
        rightMap.addLayer({
          id: fillLayerId,
          type: 'fill',
          source: sourceId,
          paint: {
            'fill-color': [
              'match',
              ['get', 'type'],
              'construction', '#FF8000', 
              'deforestation', '#FF0000', 
              'water_body', '#00FFFF',
              '#00FF00' // default
            ],
            'fill-opacity': 0.4
          }
        })
        
        rightMap.addLayer({
          id: lineLayerId,
          type: 'line',
          source: sourceId,
          paint: {
            'line-color': [
              'match',
              ['get', 'type'],
              'construction', '#FF8000', 
              'deforestation', '#FF0000', 
              'water_body', '#00FFFF',
              '#00FF00' // default
            ],
            'line-width': 2
          }
        })
      } else {
        (rightMap.getSource(sourceId) as maplibregl.GeoJSONSource).setData(geojsonData as any)
      }
    } else {
      if (rightMap.getLayer(fillLayerId)) rightMap.removeLayer(fillLayerId)
      if (rightMap.getLayer(lineLayerId)) rightMap.removeLayer(lineLayerId)
      if (rightMap.getSource(sourceId)) rightMap.removeSource(sourceId)
    }

  }, [activeLayers, changeResults, isMapLoaded])

  // Compute common map styles (excluding clipPath)
  const computeMapStyle = () => {
    if (activeLayers.includes('satellite')) return {}
    if (mapTheme === 'dark') return { filter: "invert(100%) hue-rotate(180deg) contrast(110%) brightness(95%)" }
    return { filter: "contrast(115%) grayscale(5%)" }
  }

  return (
    <div className="relative w-full h-full overflow-hidden">
      {/* Container for LEFT MapLibre Instance (Baseline) */}
      <div 
        ref={mapContainerLeft} 
        className="w-full h-full map-container absolute inset-0 z-0 bg-[#0B0F14] transition-all duration-300" 
        style={computeMapStyle()}
      />

      {/* Container for RIGHT MapLibre Instance (Current / Changes Overlay) */}
      <div 
        ref={mapContainerRight} 
        className="w-full h-full map-container absolute inset-0 z-0 transition-all duration-300" 
        style={{
          ...computeMapStyle(),
          clipPath: isSplitMode ? `inset(0 0 0 ${splitPosition}%)` : 'inset(0 0 0 0)'
        }}
      />
      
      {/* UI Overlay: Split-View Slider, sits OUTSIDE the filtered map container, rendering normally */}
      {isSplitMode && (
        <div className="absolute inset-0 z-10 pointer-events-none flex flex-col">
          <div className="w-full flex justify-between px-6 pt-4">
            <span className="bg-black/80 backdrop-blur text-astraeus-textMuted text-[10px] uppercase tracking-widest px-3 py-1.5 rounded border border-white/5">2024 (Baseline)</span>
            <span className="bg-black/80 backdrop-blur text-astraeus-primary text-[10px] uppercase tracking-widest px-3 py-1.5 rounded border border-astraeus-primary/20">2025 (Current)</span>
          </div>

          <div 
            className="absolute top-0 bottom-0 pointer-events-auto cursor-ew-resize flex items-center justify-center group"
            style={{ left: `${splitPosition}%` }}
            onMouseDown={() => {
              const handleMouseMove = (mvEvent: MouseEvent) => {
                const newPos = (mvEvent.clientX / window.innerWidth) * 100
                setSplitPosition(Math.max(10, Math.min(newPos, 90)))
              }
              const handleMouseUp = () => {
                document.removeEventListener('mousemove', handleMouseMove)
                document.removeEventListener('mouseup', handleMouseUp)
              }
              document.addEventListener('mousemove', handleMouseMove)
              document.addEventListener('mouseup', handleMouseUp)
            }}
          >
            <div className="w-0.5 h-full bg-astraeus-primary/50 group-hover:bg-astraeus-primary transition-colors shadow-[0_0_10px_rgba(59,130,246,0.5)]"></div>
            
            <div className="absolute w-8 h-12 bg-astraeus-panel border border-astraeus-primary rounded shadow-[0_0_15px_rgba(59,130,246,0.3)] flex items-center justify-center transition-transform group-hover:scale-110">
              <Columns className="w-4 h-4 text-astraeus-text" />
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

export default MapContainer
